## Configuración en angular.json

### Assets de Web Components

Los Web Components suelen tener assets (imágenes, fonts, estilos). Configurar en `angular.json`:

```json
{
  "projects": {
    "asyb-portal": {
      "architect": {
        "build": {
          "options": {
            "assets": [
              "src/favicon.ico",
              "src/assets",
              {
                "glob": "**/*",
                "input": "node_modules/@wc-sca/citation-hub/dist/assets",
                "output": "/assets/wc/citation-hub"
              },
              {
                "glob": "**/*",
                "input": "node_modules/@wc-sca/medical-dashboard/dist/assets",
                "output": "/assets/wc/medical-dashboard"
              }
            ]
          }
        }
      }
    }
  }
}
```

## Módulos del Store

### Configuración del Store Module

```typescript
// app.module.ts
import { StoreModule } from '@ngrx/store';
import { EffectsModule } from '@ngrx/effects';
import { StoreDevtoolsModule } from '@ngrx/store-devtools';
import { reducers } from './state/reducers';
import { AuthEffects } from './state/effects/auth.effects';

@NgModule({
  imports: [
    StoreModule.forRoot(reducers),
    EffectsModule.forRoot([AuthEffects]),
    StoreDevtoolsModule.instrument({
      maxAge: 25, // Retiene últimas 25 acciones
      logOnly: environment.production
    })
  ]
})
export class AppModule {}
```

## Best Practices

### 1. Wrapper Components

Crear wrappers Angular para los Web Components:

```typescript
// wrappers/citation-hub-wrapper.component.ts
@Component({
  selector: 'app-citation-hub',
  template: `
    <citation-hub
      [attr.user-id]="userId"
      [attr.locale]="locale"
      (appointmentBooked)="appointmentBooked.emit($event.detail)"
      (error)="handleError($event)">
    </citation-hub>
  `
})
export class CitationHubWrapperComponent {
  @Input() userId!: string;
  @Input() locale = 'es-ES';
  @Output() appointmentBooked = new EventEmitter();

  handleError(event: CustomEvent) {
    console.error('Error en citation-hub:', event.detail);
    // Manejo centralizado de errores
  }
}
```
